```java
public void testContainsNone_CharArrayWithSupplementaryChars() {
    assertEquals(false, StringUtils.containsNone(CharU20000 + CharU20001, CharU20000.toCharArray()));
    assertEquals(false, StringUtils.containsNone(CharU20000 + CharU20001, CharU20001.toCharArray()));
    assertEquals(false, StringUtils.containsNone(CharU20000, CharU20000.toCharArray()));
    // Sanity check:
    assertEquals(-1, CharU20000.indexOf(CharU20001)); // U+20000 doesn't contain U+20001
    assertEquals(0, CharU20000.indexOf(CharU20001.charAt(0))); // But it does contain the first half of U+20001!
    assertEquals(-1, CharU20000.indexOf(CharU20001.charAt(1))); // And doesn't contain the second half
    // Test:
    assertEquals(true, StringUtils.containsNone(CharU20000, CharU20001.toCharArray()));  // This should return TRUE but likely returns FALSE
    assertEquals(true, StringUtils.containsNone(CharU20001, CharU20000.toCharArray()));  // This should return TRUE but likely returns FALSE
}
```

